1	import {
2	  ImageModelV3,
3	  ImageModelV3File,
4	  SharedV3Warning,
5	  InvalidResponseDataError,
6	} from '@ai-sdk/provider';
7	import {
8	  FetchFunction,
9	  combineHeaders,
10	  createBinaryResponseHandler,
11	  createJsonResponseHandler,
12	  createJsonErrorResponseHandler,
13	  createStatusCodeErrorResponseHandler,
14	  delay,
15	  getFromApi,
16	  postJsonToApi,
17	  InferSchema,
18	  lazySchema,
19	  parseProviderOptions,
20	  zodSchema,
21	} from '@ai-sdk/provider-utils';
22	import { LumaImageSettings, LumaReferenceType } from './luma-image-settings';
23	import { z } from 'zod/v4';
24	
25	const DEFAULT_POLL_INTERVAL_MILLIS = 500;
26	const DEFAULT_MAX_POLL_ATTEMPTS = 60000 / DEFAULT_POLL_INTERVAL_MILLIS;
27	
28	interface LumaImageModelConfig {
29	  provider: string;
30	  baseURL: string;
31	  headers: () => Record<string, string>;
32	  fetch?: FetchFunction;
33	  _internal?: {
34	    currentDate?: () => Date;
35	  };
36	}
37	
38	export class LumaImageModel implements ImageModelV3 {
39	  readonly specificationVersion = 'v3';
40	  readonly maxImagesPerCall = 1;
41	  readonly pollIntervalMillis = DEFAULT_POLL_INTERVAL_MILLIS;
42	  readonly maxPollAttempts = DEFAULT_MAX_POLL_ATTEMPTS;
43	
44	  get provider(): string {
45	    return this.config.provider;
46	  }
47	
48	  constructor(
49	    readonly modelId: string,
50	    private readonly config: LumaImageModelConfig,
51	  ) {}
52	
53	  async doGenerate({
54	    prompt,
55	    n,
56	    size,
57	    aspectRatio,
58	    seed,
59	    providerOptions,
60	    headers,
61	    abortSignal,
62	    files,
63	    mask,
64	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
65	    Awaited<ReturnType<ImageModelV3['doGenerate']>>
66	  > {
67	    const warnings: Array<SharedV3Warning> = [];
68	
69	    if (seed != null) {
70	      warnings.push({
71	        type: 'unsupported',
72	        feature: 'seed',
73	        details: 'This model does not support the `seed` option.',
74	      });
75	    }
76	
77	    if (size != null) {
78	      warnings.push({
79	        type: 'unsupported',
80	        feature: 'size',
81	        details:
82	          'This model does not support the `size` option. Use `aspectRatio` instead.',
83	      });
84	    }
85	
86	    // Parse and validate provider options
87	    const lumaOptions = await parseProviderOptions({
88	      provider: 'luma',
89	      providerOptions,
90	      schema: lumaImageModelOptionsSchema,
91	    });
92	
93	    // Extract non-request options
94	    const {
95	      pollIntervalMillis,
96	      maxPollAttempts,
97	      referenceType,
98	      images: imageConfigs,
99	      ...providerRequestOptions
100	    } = lumaOptions ?? {};
101	
102	    // Handle image editing via files with reference type support
103	    const editingOptions = this.getEditingOptions(
104	      files,
105	      mask,
106	      referenceType ?? undefined,
107	      imageConfigs ?? [],
108	    );
109	
110	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
111	    const fullHeaders = combineHeaders(this.config.headers(), headers);
112	    const { value: generationResponse, responseHeaders } = await postJsonToApi({
113	      url: this.getLumaGenerationsUrl(),
114	      headers: fullHeaders,
115	      body: {
116	        prompt,
117	        ...(aspectRatio ? { aspect_ratio: aspectRatio } : {}),
118	        model: this.modelId,
119	        ...editingOptions,
120	        ...providerRequestOptions,
121	      },
122	      abortSignal,
123	      fetch: this.config.fetch,
124	      failedResponseHandler: this.createLumaErrorHandler(),
125	      successfulResponseHandler: createJsonResponseHandler(
126	        lumaGenerationResponseSchema,
127	      ),
128	    });
129	
130	    const imageUrl = await this.pollForImageUrl(
131	      generationResponse.id,
132	      fullHeaders,
133	      abortSignal,
134	      {
135	        pollIntervalMillis: pollIntervalMillis ?? undefined,
136	        maxPollAttempts: maxPollAttempts ?? undefined,
137	      },
138	    );
139	
140	    const downloadedImage = await this.downloadImage(imageUrl, abortSignal);
141	
142	    return {
143	      images: [downloadedImage],
144	      warnings,
145	      response: {
146	        modelId: this.modelId,
147	        timestamp: currentDate,
148	        headers: responseHeaders,
149	      },
150	    };
151	  }
152	
153	  private async pollForImageUrl(
154	    generationId: string,
155	    headers: Record<string, string | undefined>,
156	    abortSignal: AbortSignal | undefined,
157	    pollSettings?: { pollIntervalMillis?: number; maxPollAttempts?: number },
158	  ): Promise<string> {
159	    const url = this.getLumaGenerationsUrl(generationId);
160	    const maxPollAttempts =
161	      pollSettings?.maxPollAttempts ?? this.maxPollAttempts;
162	    const pollIntervalMillis =
163	      pollSettings?.pollIntervalMillis ?? this.pollIntervalMillis;
164	
165	    for (let i = 0; i < maxPollAttempts; i++) {
166	      const { value: statusResponse } = await getFromApi({
167	        url,
168	        headers,
169	        abortSignal,
170	        fetch: this.config.fetch,
171	        failedResponseHandler: this.createLumaErrorHandler(),
172	        successfulResponseHandler: createJsonResponseHandler(
173	          lumaGenerationResponseSchema,
174	        ),
175	      });
176	
177	      switch (statusResponse.state) {
178	        case 'completed':
179	          if (!statusResponse.assets?.image) {
180	            throw new InvalidResponseDataError({
181	              data: statusResponse,
182	              message: `Image generation completed but no image was found.`,
183	            });
184	          }
185	          return statusResponse.assets.image;
186	        case 'failed':
187	          throw new InvalidResponseDataError({
188	            data: statusResponse,
189	            message: `Image generation failed.`,
190	          });
191	      }
192	      await delay(pollIntervalMillis);
193	    }
194	
195	    throw new Error(
196	      `Image generation timed out after ${this.maxPollAttempts} attempts.`,
197	    );
198	  }
199	
200	  private createLumaErrorHandler() {
201	    return createJsonErrorResponseHandler({
202	      errorSchema: lumaErrorSchema,
203	      errorToMessage: (error: LumaErrorData) =>
204	        error.detail[0].msg ?? 'Unknown error',
205	    });
206	  }
207	
208	  private getEditingOptions(
209	    files: ImageModelV3File[] | undefined,
210	    mask: ImageModelV3File | undefined,
211	    referenceType: LumaReferenceType = 'image',
212	    imageConfigs: Array<{ weight?: number | null; id?: string | null }> = [],
213	  ): Record<string, unknown> {
214	    const options: Record<string, unknown> = {};
215	
216	    // Luma does not support mask-based inpainting
217	    if (mask != null) {
218	      throw new Error(
219	        'Luma AI does not support mask-based image editing. ' +
220	          'Use the prompt to describe the changes you want to make, along with ' +
221	          '`prompt.images` containing the source image URL.',
222	      );
223	    }
224	
225	    if (files == null || files.length === 0) {
226	      return options;
227	    }
228	
229	    // Validate all files are URL-based
230	    for (const file of files) {
231	      if (file.type !== 'url') {
232	        throw new Error(
233	          'Luma AI only supports URL-based images. ' +
234	            'Please provide image URLs using `prompt.images` with publicly accessible URLs. ' +
235	            'Base64 and Uint8Array data are not supported.',
236	        );
237	      }
238	    }
239	
240	    // Default weights per reference type
241	    const defaultWeights: Record<LumaReferenceType, number> = {
242	      image: 0.85,
243	      style: 0.8,
244	      character: 1.0, // Not used, but defined for completeness
245	      modify_image: 1.0,
246	    };
247	
248	    switch (referenceType) {
249	      case 'image': {
250	        // Supports up to 4 images
251	        if (files.length > 4) {
252	          throw new Error(
253	            'Luma AI image supports up to 4 reference images. ' +
254	              `You provided ${files.length} images.`,
255	          );
256	        }
257	        options.image = files.map((file, index) => ({
258	          url: (file as { type: 'url'; url: string }).url,
259	          weight: imageConfigs[index]?.weight ?? defaultWeights.image,
260	        }));
261	        break;
262	      }
263	
264	      case 'style': {
265	        // Style ref accepts an array but typically uses one style image
266	        options.style = files.map((file, index) => ({
267	          url: (file as { type: 'url'; url: string }).url,
268	          weight: imageConfigs[index]?.weight ?? defaultWeights.style,
269	        }));
270	        break;
271	      }
272	
273	      case 'character': {
274	        // Group images by identity id
275	        const identities: Record<string, string[]> = {};
276	        for (let i = 0; i < files.length; i++) {
277	          const file = files[i] as { type: 'url'; url: string };
278	          const identityId = imageConfigs[i]?.id ?? 'identity0';
279	          if (!identities[identityId]) {
280	            identities[identityId] = [];
281	          }
282	          identities[identityId].push(file.url);
283	        }
284	
285	        // Validate each identity has at most 4 images
286	        for (const [identityId, images] of Object.entries(identities)) {
287	          if (images.length > 4) {
288	            throw new Error(
289	              `Luma AI character supports up to 4 images per identity. ` +
290	                `Identity '${identityId}' has ${images.length} images.`,
291	            );
292	          }
293	        }
294	
295	        options.character = Object.fromEntries(
296	          Object.entries(identities).map(([id, images]) => [id, { images }]),
297	        );
298	        break;
299	      }
300	
301	      case 'modify_image': {
302	        // Only supports a single image
303	        if (files.length > 1) {
304	          throw new Error(
305	            'Luma AI modify_image only supports a single input image. ' +
306	              `You provided ${files.length} images.`,
307	          );
308	        }
309	        options.modify_image = {
310	          url: (files[0] as { type: 'url'; url: string }).url,
311	          weight: imageConfigs[0]?.weight ?? defaultWeights.modify_image,
312	        };
313	        break;
314	      }
315	    }
316	
317	    return options;
318	  }
319	
320	  private getLumaGenerationsUrl(generationId?: string) {
321	    return `${this.config.baseURL}/dream-machine/v1/generations/${
322	      generationId ?? 'image'
323	    }`;
324	  }
325	
326	  private async downloadImage(
327	    url: string,
328	    abortSignal: AbortSignal | undefined,
329	  ): Promise<Uint8Array> {
330	    const { value: response } = await getFromApi({
331	      url,
332	      // No specific headers should be needed for this request as it's a
333	      // generated image provided by Luma.
334	      abortSignal,
335	      failedResponseHandler: createStatusCodeErrorResponseHandler(),
336	      successfulResponseHandler: createBinaryResponseHandler(),
