5	/**
6	 * Wraps an ImageModelV3 instance with middleware functionality.
7	 * This function allows you to apply middleware to transform parameters
8	 * and wrap generate operations of an image model.
9	 *
10	 * @param options - Configuration options for wrapping the image model.
11	 * @param options.model - The original ImageModelV3 instance to be wrapped.
12	 * @param options.middleware - The middleware to be applied to the image model. When multiple middlewares are provided, the first middleware will transform the input first, and the last middleware will be wrapped directly around the model.
13	 * @param options.modelId - Optional custom model ID to override the original model's ID.
14	 * @param options.providerId - Optional custom provider ID to override the original model's provider ID.
15	 * @returns A new ImageModelV3 instance with middleware applied.
16	 */
17	export const wrapImageModel = ({
18	  model,
19	  middleware: middlewareArg,
20	  modelId,
21	  providerId,
22	}: {
23	  model: ImageModelV3;
24	  middleware: ImageModelMiddleware | ImageModelMiddleware[];
25	  modelId?: string;
26	  providerId?: string;
27	}): ImageModelV3 => {
28	  return [...asArray(middlewareArg)]
29	    .reverse()
30	    .reduce((wrappedModel, middleware) => {
31	      return doWrap({ model: wrappedModel, middleware, modelId, providerId });
32	    }, model);
33	};
