```typescript
interface OpenAIImageModelConfig extends OpenAIConfig {
  _internal?: {
    currentDate?: () => Date;
  };
}

export class OpenAIImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    return modelMaxImagesPerCall[this.modelId] ?? 1;
  }

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: OpenAIImageModelId,
    private readonly config: OpenAIImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    files,
    mask,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    // Check for unsupported features
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'This model does not support aspect ratio. Use `size` instead.',
      });
    }

    if (seed != null) {
      warnings.push({ type: 'unsupported', feature: 'seed' });
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    // Handle image editing with files (mask for inpainting)
    if (files != null) {
      const { value: response, responseHeaders } = await postFormDataToApi({
        url: this.config.url({
          path: '/images/edits',
          modelId: this.modelId,
        }),
        headers: combineHeaders(this.config.headers(), headers),
        formData: convertToFormData<OpenAIImageEditInput>({
          model: this.modelId,
          prompt,
          image: await Promise.all(
            files.map(file =>
              file.type === 'file'
                ? new Blob([...], { type: file.mediaType })
                : downloadBlob(file.url),
            ),
          ),
          mask: mask != null ? await fileToBlob(mask) : undefined,
          n,
          size,
          ...(providerOptions.openai ?? {}),
        }),
        failedResponseHandler: openaiFailedResponseHandler,
        successfulResponseHandler: createJsonResponseHandler(
          openaiImageResponseSchema,
        ),
        abortSignal,
        fetch: this.config.fetch,
      });

      return {
        images: response.data.map(item => item.b64_json),
        warnings,
        usage: { inputTokens, outputTokens, totalTokens },
        response: { timestamp: currentDate, modelId: this.modelId, headers: responseHeaders },
        providerMetadata: {
          openai: {
            images: response.data.map((item, index) => ({
              revisedPrompt: item.revised_prompt,
              created: response.created,
              size: response.size,
              quality: response.quality,
            })),
          },
        },
      };
    }

    // Handle text-to-image generation
    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.url({
        path: '/images/generations',
        modelId: this.modelId,
      }),
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        size,
        ...(providerOptions.openai ?? {}),
      },
      // ... handlers ...
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      usage: { ... },
      response: { ... },
      providerMetadata: { ... },
    };
  }
}
```

### FAL Image Model Class

**File:** `packages/fal/src/fal-image-model.ts`

```typescript
interface FalImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class FalImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: FalImageModelId,
    private readonly config: FalImageModelConfig,
  ) {}

  private async getArgs({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]) {
    const warnings: Array<SharedV3Warning> = [];

    let imageSize: FalImageSize | undefined;
    if (size) {
      const [width, height] = size.split('x').map(Number);
      imageSize = { width, height };
    } else if (aspectRatio) {
      imageSize = convertAspectRatioToSize(aspectRatio);
    }

    const falOptions = await parseProviderOptions({
      provider: 'fal',
      providerOptions,
      schema: falImageModelOptionsSchema,
    });

    const requestBody: Record<string, unknown> = {
      prompt,
      seed,
      image_size: imageSize,
      num_images: n,
    };

    // Handle image editing: convert files to image_url or image_urls
    if (files != null && files.length > 0) {
      const useMultipleImages = falOptions?.useMultipleImages === true;

      if (useMultipleImages) {
        requestBody.image_urls = files.map(file =>
          convertImageModelFileToDataUri(file),
        );
      } else {
        requestBody.image_url = convertImageModelFileToDataUri(files[0]);
        if (files.length > 1) {
          warnings.push({
            type: 'other',
            message: 'Multiple input images provided but useMultipleImages is not enabled.',
          });
        }
      }
    }

    // Handle mask for inpainting
    if (mask != null) {
      requestBody.mask_url = convertImageModelFileToDataUri(mask);
    }

    if (falOptions) {
      // Handle deprecated snake_case keys
      const fieldMapping: Record<string, string> = {
        imageUrl: 'image_url',
        maskUrl: 'mask_url',
        guidanceScale: 'guidance_scale',
        numInferenceSteps: 'num_inference_steps',
        enableSafetyChecker: 'enable_safety_checker',
        outputFormat: 'output_format',
        syncMode: 'sync_mode',
        safetyTolerance: 'safety_tolerance',
      };

      for (const [key, value] of Object.entries(falOptions)) {
        if (key === '__deprecatedKeys') continue;
        if (key === 'useMultipleImages') continue; // Don't send to API
        const apiKey = fieldMapping[key] ?? key;
        if (value !== undefined) {
          requestBody[apiKey] = value;
        }
      }
    }

    return { requestBody, warnings } as const;
  }

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const { requestBody, warnings } = await this.getArgs(options);

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/${this.modelId}`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        options.headers,
      ),
      body: requestBody,
      failedResponseHandler: falFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        falImageResponseSchema,
      ),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    // Download the images
    const downloadedImages = await Promise.all(
      value.images.map(image =>
        this.downloadImage(image.url, options.abortSignal),
      ),
    );

    return {
      images: downloadedImages,
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
      providerMetadata: {
        fal: {
          images: value.images.map((image, index) => ({
            ...imageMetaData,
            contentType,
            fileName,
            nsfw: has_nsfw_concepts?.[index],
          })),
        },
      },
    };
  }

  private async downloadImage(
    url: string,
    abortSignal: AbortSignal | undefined,
  ): Promise<Uint8Array> {
    const { value: response } = await getFromApi({
      url,
      abortSignal,
      failedResponseHandler: createStatusCodeErrorResponseHandler(),
      successfulResponseHandler: createBinaryResponseHandler(),
      fetch: this.config.fetch,
    });
    return response;
  }
}
```

**Key Differences:**
- **OpenAI:** Directly returns base64-encoded images in response
- **FAL:** Downloads images from URLs provided in response
- **OpenAI:** Maps to model-specific image counts via `modelMaxImagesPerCall`
- **FAL:** Fixed at 1 image per call

