## 5. PROVIDER FACTORY FUNCTION PATTERN

### OpenAI Example (openai-provider.ts)

```typescript
export interface OpenAIProvider extends ProviderV3 {
  (modelId: OpenAIResponsesModelId): LanguageModelV3;
  languageModel(modelId: OpenAIResponsesModelId): LanguageModelV3;
  chat(modelId: OpenAIChatModelId): LanguageModelV3;
  responses(modelId: OpenAIResponsesModelId): LanguageModelV3;
  completion(modelId: OpenAICompletionModelId): LanguageModelV3;
  embedding(modelId: OpenAIEmbeddingModelId): EmbeddingModelV3;
  image(modelId: OpenAIImageModelId): ImageModelV3;
  transcription(modelId: OpenAITranscriptionModelId): TranscriptionModelV3;
  speech(modelId: OpenAISpeechModelId): SpeechModelV3;
  tools: typeof openaiTools;
}

export interface OpenAIProviderSettings {
  baseURL?: string;
  apiKey?: string;
  organization?: string;
  project?: string;
  headers?: Record<string, string>;
  name?: string;
  fetch?: FetchFunction;
}

export function createOpenAI(
  options: OpenAIProviderSettings = {},
): OpenAIProvider {
  const baseURL = withoutTrailingSlash(
    loadOptionalSetting({
      settingValue: options.baseURL,
      environmentVariableName: 'OPENAI_BASE_URL',
    }),
  ) ?? 'https://api.openai.com/v1';

  const providerName = options.name ?? 'openai';

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'OPENAI_API_KEY',
          description: 'OpenAI',
        })}`,
        'OpenAI-Organization': options.organization,
        'OpenAI-Project': options.project,
        ...options.headers,
      },
      `ai-sdk/openai/${VERSION}`,
    );

  const createImageModel = (modelId: OpenAIImageModelId) =>
    new OpenAIImageModel(modelId, {
      provider: `${providerName}.image`,
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  // ... Other model creators ...

  const provider = function (modelId: OpenAIResponsesModelId) {
    return createLanguageModel(modelId);
  };

  provider.specificationVersion = 'v3' as const;
  provider.languageModel = createLanguageModel;
  provider.chat = createChatModel;
  provider.image = createImageModel;
  // ... Attach all model creators ...
  provider.tools = openaiTools;

  return provider as OpenAIProvider;
}

export const openai = createOpenAI();
```

### FAL Example (fal-provider.ts)

```typescript
export interface FalProvider extends ProviderV3 {
  image(modelId: FalImageModelId): ImageModelV3;
  imageModel(modelId: FalImageModelId): ImageModelV3;
  transcription(modelId: FalTranscriptionModelId): TranscriptionModelV3;
  video(modelId: FalVideoModelId): Experimental_VideoModelV3;
  videoModel(modelId: FalVideoModelId): Experimental_VideoModelV3;
  speech(modelId: FalSpeechModelId): SpeechModelV3;
}

export interface FalProviderSettings {
  apiKey?: string;
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export function createFal(options: FalProviderSettings = {}): FalProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Key ${loadFalApiKey({
          apiKey: options.apiKey,
        })}`,
        ...options.headers,
      },
      `ai-sdk/fal/${VERSION}`,
    );

  const createImageModel = (modelId: FalImageModelId) =>
    new FalImageModel(modelId, {
      provider: 'fal.image',
      baseURL: baseURL ?? defaultBaseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  // ... Other model creators ...

  return {
    specificationVersion: 'v3' as const,
    imageModel: createImageModel,
    image: createImageModel,
    // ... Other model factories ...
  };
}

export const fal = createFal();
```

**Key Pattern:**
1. Define `ProviderInterface` extending `ProviderV3`
2. Define `ProviderSettings` interface for configuration
3. Create `createProvider()` factory function
4. Attach model factory methods to a base function object
5. Export default instance: `export const provider = createProvider()`

