export const VERSION: string =
  typeof __PACKAGE_VERSION__ !== 'undefined'
    ? __PACKAGE_VERSION__
    : '0.0.0-test';
```

### 9. `packages/pixelart/src/pixelart-image-settings.ts`
Defines the union type of known model IDs plus the open-ended escape hatch:
```typescript
export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | 'pixelart-retro'
  | (string & {});
```
No additional settings type needed for this provider (size is standard, style/density go in options).

### 10. `packages/pixelart/src/pixelart-image-options.ts`
Provider-specific options schema using `lazySchema` + `zodSchema` pattern:
- `style`: `z.enum(['pixel', 'retro', '8bit']).nullish()`
- `pixelDensity`: `z.number().int().min(1).nullish()` — pixels per unit (e.g., 8, 16, 32)

```typescript
import { InferSchema, lazySchema, zodSchema } from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      style: z.enum(['pixel', 'retro', '8bit']).nullish(),
      pixelDensity: z.number().int().min(1).nullish(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;
```

### 11. `packages/pixelart/src/pixelart-image-model.ts`
The core image model class:

**Config interface:**
```typescript
interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  _internal?: { currentDate?: () => Date };
}
```

**Class fields:**
- `specificationVersion = 'v3'` (literal)
- `maxImagesPerCall = 1`
- `get provider()` — returns `this.config.provider`
- `constructor(readonly modelId, private readonly config)`

**`doGenerate()` logic:**
1. Collect `warnings: Array<SharedV3Warning> = []`
2. Warn + ignore if `aspectRatio` is provided (provider only supports `size`, not aspect ratio)
3. Parse `providerOptions.pixelart` via `parseProviderOptions({ provider: 'pixelart', providerOptions, schema: pixelArtImageModelOptionsSchema })`
4. Build request body:
   ```json
   {
     "model": "<modelId>",
     "prompt": "<prompt>",
     "n": <n>,
     "size": "<size or undefined>",
     "style": "<style or undefined>",
     "pixel_density": <pixelDensity or undefined>
   }
   ```
5. Call `postJsonToApi({ url: baseURL + '/images/generate', ... })`
6. Parse response using `createJsonResponseHandler(pixelArtImageResponseSchema)`
7. Return `{ images: response.data.map(item => decodeBase64(item.b64_json)), warnings, response: { timestamp, modelId, headers }, providerMetadata: { pixelart: { ... } } }`

**Response schema (Zod):**
```typescript
const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      created: z.number().nullish(),
      data: z.array(z.object({ b64_json: z.string() })),
    }),
  ),
);
```

**Error schema:**
```typescript
const pixelArtErrorSchema = z.object({ error: z.object({ message: z.string() }) });
const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => error.error.message,
});
```

**Base64 → Uint8Array conversion:**
Use `convertBase64ToUint8Array` from `@ai-sdk/provider-utils`.

### 12. `packages/pixelart/src/pixelart-provider.ts`
Provider factory:

```typescript
export interface PixelArtProviderSettings {
  apiKey?: string;
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  image(modelId: PixelArtImageModelId): ImageModelV3;
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

const DEFAULT_BASE_URL = 'https://api.pixelart.ai/v1';

export function createPixelArt(options: PixelArtProviderSettings = {}): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? DEFAULT_BASE_URL);
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
