import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const TEST_BASE_URL = 'https://api.example.com/v1';
const TEST_MODEL_ID = 'pixelart-v1';
const TEST_PROMPT = 'A pixel art castle at sunset';

// "test-image-data" encoded as base64
const TEST_B64 = Buffer.from('test-image-data').toString('base64');

const MOCK_RESPONSE = {
  created: 1700000000,
  data: [{ b64_json: TEST_B64 }],
};

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel(TEST_MODEL_ID, {
    provider: 'pixelart.image',
    baseURL: TEST_BASE_URL,
    headers: headers ? () => headers : () => ({ Authorization: 'Bearer test-key' }),
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    [`${TEST_BASE_URL}/images/generate`]: {
      response: {
        type: 'json-value',
        body: MOCK_RESPONSE,
      },
    },
  });

  describe('doGenerate', () => {
    it('should pass model, prompt, and n in the request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: TEST_MODEL_ID,
        prompt: TEST_PROMPT,
        n: 1,
      });
    });

    it('should forward the size parameter', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: TEST_MODEL_ID,
        prompt: TEST_PROMPT,
        n: 1,
        size: '512x512',
      });
    });

    it('should forward the seed parameter', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: TEST_MODEL_ID,
        prompt: TEST_PROMPT,
        n: 1,
        seed: 42,
      });
    });

    it('should send style as a top-level field', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { style: 'retro' } },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: TEST_MODEL_ID,
        prompt: TEST_PROMPT,
        n: 1,
        style: 'retro',
      });
    });

    it('should send pixelDensity as pixel_density', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { pixelDensity: 16 } },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: TEST_MODEL_ID,
        prompt: TEST_PROMPT,
        n: 1,
        pixel_density: 16,
      });
    });

    it('should send all provider options together with size', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        files: undefined,
        mask: undefined,
        n: 2,
        size: '256x256',
        aspectRatio: undefined,
        seed: 99,
        providerOptions: { pixelart: { style: '8bit', pixelDensity: 8 } },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: TEST_MODEL_ID,
        prompt: TEST_PROMPT,
        n: 2,
        size: '256x256',
        seed: 99,
        style: '8bit',
        pixel_density: 8,
      });
    });

    it('should emit an unsupported warning for aspectRatio', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toHaveLength(1);
      expect(result.warnings[0]).toMatchObject({
        type: 'unsupported',
        feature: 'aspectRatio',
      });
    });

    it('should return Uint8Array images decoded from base64', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
      expect(Buffer.from(result.images[0] as Uint8Array).toString()).toBe(
        'test-image-data',
      );
    });

    it('should include provider metadata with created timestamp', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.providerMetadata?.pixelart).toMatchObject({
        created: 1700000000,
      });
    });

    it('should include the correct response modelId and timestamp', async () => {
      const testDate = new Date('2024-01-01T00:00:00Z');
      const model = createBasicModel({ currentDate: () => testDate });

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.response.modelId).toBe(TEST_MODEL_ID);
      expect(result.response.timestamp).toEqual(testDate);
    });

    it('should use the correct endpoint URL', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(server.calls[0].requestUrl).toBe(
        `${TEST_BASE_URL}/images/generate`,
      );
    });

    it('should send Authorization header', async () => {
      const model = createBasicModel({
        headers: { Authorization: 'Bearer my-test-key' },
      });

      await model.doGenerate({
        prompt: TEST_PROMPT,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(server.calls[0].requestHeaders['authorization']).toBe(
        'Bearer my-test-key',
      );
    });
  });
});

